import { registerInterest } from "../interest/registerInterestFunction.svelte";
import { isFound } from "../network/loadable";
import { UserService } from "./userService";
import { userTable, userByLoginTable } from "./usersSlice";
export function getUserByLogin(appState, userService, login) {
    registerInterest(userService.getUserByLoginInterest(login));
    const currentUserId = $derived(userByLoginTable.selectors.selectById(appState.usersByLogin, login));
    const current = $derived.by(() => {
        if (!currentUserId)
            return undefined;
        if (!isFound(currentUserId))
            return currentUserId;
        const id = currentUserId.value;
        return userTable.selectors.selectById(appState.users, id);
    });
    return {
        get current() {
            return current;
        },
    };
}
