<script lang="ts">import Loading from "../network/Loading.svelte";
import { isFound } from "../network/loadable";
import { ORGANIZATION_SERVICE } from "./organizationService";
import { getOrganizationBySlug } from "./organizationsPreview.svelte";
import { getProjectByRepositoryId } from "./projectsPreview.svelte";
import { APP_STATE } from "../redux/store.svelte";
import { USER_SERVICE } from "../users/userService";
import { getUserByLogin } from "../users/usersPreview.svelte";
import { inject } from "@gitbutler/core/context";
import { Avatar, Button, CardGroup, Modal, Textbox } from "@gitbutler/ui";
const { slug } = $props();
const appState = inject(APP_STATE);
const organizationService = inject(ORGANIZATION_SERVICE);
const userService = inject(USER_SERVICE);
const organization = $derived(getOrganizationBySlug(appState, organizationService, slug));
const title = $derived.by(() => {
  if (!isFound(organization.current)) return "";
  return organization.current.value.name || organization.current.value.slug;
});
function onModalClose() {
}
let modal = $state();
</script>

<Modal bind:this={modal} onClose={onModalClose} {title}>
	<Loading loadable={organization.current}>
		{#snippet children(organization)}
			{#if organization.inviteCode}
				<div class="header-with-action">
					<p>Invite code:</p>
					<Textbox value={organization.inviteCode} readonly></Textbox>
				</div>
			{/if}

			{#if organization.memberLogins}
				<h5 class="text-15 text-bold">Users:</h5>

				<CardGroup>
					{#each organization.memberLogins as login}
						{@const user = getUserByLogin(appState, userService, login)}

						<CardGroup.Item>
							<Loading loadable={user.current}>
								{#snippet children(user)}
									<Avatar
										size="medium"
										username={user?.name || "Unknown"}
										srcUrl={user?.avatarUrl || ""}
									/>
									<p>{user?.name}</p>
								{/snippet}
							</Loading>
						</CardGroup.Item>
					{/each}
				</CardGroup>
			{/if}

			{#if organization.projectRepositoryIds}
				<h5 class="text-15 text-bold">Projects:</h5>
				<CardGroup>
					{#each organization.projectRepositoryIds as repositoryId}
						{@const project = getProjectByRepositoryId(repositoryId)}

						<CardGroup.Item>
							<Loading loadable={project.current}>
								{#snippet children(project)}
									<p>{project.name}</p>
								{/snippet}
							</Loading>
						</CardGroup.Item>
					{/each}
				</CardGroup>
			{/if}
		{/snippet}
	</Loading>
</Modal>

<Button onclick={() => modal?.show()}>View</Button>

<style>
	.header-with-action {
		display: flex;
		align-items: center;
		justify-content: space-between;

		margin-bottom: 0.5rem;
	}
</style>
