import { registerInterest } from "../interest/registerInterestFunction.svelte";
import { map } from "../network/loadable";
import { organizationTable } from "./organizationsSlice";
import { projectTable } from "./projectsSlice";
export function getOrganizations(appState, organizationService, inView) {
    registerInterest(organizationService.getOrganizationListingInterest(), inView);
    const current = $derived(organizationTable.selectors.selectAll(appState.organizations));
    return {
        get current() {
            return current;
        },
    };
}
export function getOrganizationBySlug(appState, organizationService, slug, inView) {
    registerInterest(organizationService.getOrganizationWithDetailsInterest(slug), inView);
    const current = $derived(organizationTable.selectors.selectById(appState.organizations, slug));
    return {
        get current() {
            return current;
        },
    };
}
export function getOrganizationProjects(appState, organizationService, slug, inView) {
    registerInterest(organizationService.getOrganizationWithDetailsInterest(slug), inView);
    const organization = $derived(organizationTable.selectors.selectById(appState.organizations, slug));
    const projects = $derived(map(organization, (organization) => (organization.projectRepositoryIds || [])
        .map((id) => projectTable.selectors.selectById(appState.projects, id))
        .filter((a) => a !== undefined)));
    return {
        get current() {
            return projects;
        },
    };
}
