import { apiToBranch } from "../branches/types";
import { InterestStore } from "../interest/interestStore";
import {} from "../network/httpClient";
import { errorToLoadable } from "../network/loadable";
import { organizationTable } from "./organizationsSlice";
import { projectTable } from "./projectsSlice";
import { apiToOrganization, apiToProject, } from "./types";
import { POLLING_REGULAR, POLLING_SLOW } from "../polling";
import { InjectionToken } from "@gitbutler/core/context";
import { writable } from "svelte/store";
export const ORGANIZATION_SERVICE = new InjectionToken("OrganizationService");
export class OrganizationService {
    httpClient;
    appDispatch;
    organizationListingInterests = new InterestStore(POLLING_SLOW);
    orgnaizationInterests = new InterestStore(POLLING_REGULAR);
    // Add the patch stack cache
    patchStackCache = new Map();
    constructor(httpClient, appDispatch) {
        this.httpClient = httpClient;
        this.appDispatch = appDispatch;
    }
    getOrganizationListingInterest() {
        return this.organizationListingInterests
            .findOrCreateSubscribable(undefined, async () => {
            const apiOrganizations = await this.httpClient.get("organization");
            const organizations = apiOrganizations.map((apiOrganizations) => ({
                status: "found",
                id: apiOrganizations.slug,
                value: apiToOrganization(apiOrganizations),
            }));
            this.appDispatch.dispatch(organizationTable.upsertMany(organizations));
        })
            .createInterest();
    }
    getOrganizationWithDetailsInterest(slug) {
        return this.orgnaizationInterests
            .findOrCreateSubscribable({ slug }, async () => {
            this.appDispatch.dispatch(organizationTable.addOne({ status: "loading", id: slug }));
            try {
                const apiOrganization = await this.httpClient.get(`organization/${slug}`);
                const projects = apiOrganization.projects.map((apiProject) => ({
                    status: "found",
                    id: apiProject.repository_id,
                    value: apiToProject(apiProject),
                }));
                this.appDispatch.dispatch(projectTable.upsertMany(projects));
                this.appDispatch.dispatch(organizationTable.upsertOne({
                    status: "found",
                    id: slug,
                    value: apiToOrganization(apiOrganization),
                }));
            }
            catch (error) {
                this.appDispatch.dispatch(organizationTable.addOne(errorToLoadable(error, slug)));
            }
        })
            .createInterest();
    }
    async createOrganization(slug, name, description) {
        const apiOrganization = await this.httpClient.post("organization", {
            body: {
                slug,
                name,
                description,
            },
        });
        const organization = apiToOrganization(apiOrganization);
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
        return organization;
    }
    async joinOrganization(slug, joinCode) {
        const apiOrganization = await this.httpClient.post(`organization/${slug}/join`, {
            body: { invite_code: joinCode },
        });
        const organization = apiToOrganization(apiOrganization);
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
        return organization;
    }
    /**
     * Gets a store for an organization's patch stacks by slug. The store will be populated when accessed.
     * @param ownerSlug The organization slug to fetch patch stacks for
     * @returns A readable store containing the patch stacks
     */
    getPatchStacks(ownerSlug) {
        if (!this.patchStackCache.has(ownerSlug)) {
            // Create a new store for this organization's patch stacks
            const store = writable({ status: "loading", ownerSlug }, (set) => {
                // Fetch data when the store is first subscribed to
                this.fetchPatchStacks(ownerSlug)
                    .then((data) => {
                    set({ status: "found", ownerSlug, value: data });
                })
                    .catch((error) => {
                    if (error.response?.status === 404) {
                        set({
                            status: "not-found",
                            ownerSlug,
                        });
                    }
                    else {
                        set({
                            status: "error",
                            ownerSlug,
                            error: error.message || "Unknown error occurred",
                        });
                    }
                });
            });
            this.patchStackCache.set(ownerSlug, store);
        }
        return this.patchStackCache.get(ownerSlug);
    }
    /**
     * Manually fetch patch stacks from the API
     * @param ownerSlug The organization slug to fetch patch stacks for
     * @returns Array of patch stacks converted to Branch format
     */
    async fetchPatchStacks(ownerSlug) {
        // Try different API endpoint patterns since we're not sure about the exact one
        const endpoint = `organization/${ownerSlug}/patch_stacks`;
        try {
            const response = await this.httpClient.get(endpoint);
            // Convert ApiBranch objects to Branch objects
            return response.map(apiToBranch);
        }
        catch (error) {
            console.error(`[OrganizationService] Error with endpoint ${endpoint}:`, error);
            // If this is not a 404 error (which likely means wrong endpoint), rethrow it
            if (error.response && error.response.status !== 404) {
                throw error;
            }
            // If it's a 404, we'll try the next endpoint
        }
        // If we've tried all endpoints and none worked, return empty array
        console.warn(`[OrganizationService] All endpoints failed, returning empty array`);
        return [];
    }
    /**
     * Remove patch stacks from the cache
     * @param ownerSlug The organization slug to remove from cache
     */
    clearPatchStackCache(ownerSlug) {
        if (ownerSlug) {
            this.patchStackCache.delete(ownerSlug);
        }
        else {
            this.patchStackCache.clear();
        }
    }
    async removeUser(slug, login) {
        const apiOrganization = await this.httpClient.post(`organization/${slug}/remove?login=${login}`, {});
        const organization = apiToOrganization(apiOrganization);
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
        return organization;
    }
    async resetInviteCode(slug) {
        const apiOrganization = await this.httpClient.post(`organization/${slug}/reset_invite_code`, {});
        const organization = apiToOrganization(apiOrganization);
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
        return organization;
    }
    async changeUserRole(slug, login, role) {
        const apiOrganization = await this.httpClient.put(`organization/${slug}/${login}?role=${role}`, {});
        const organization = apiToOrganization(apiOrganization);
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
        return organization;
    }
    async getOrganizationBySlug(slug) {
        try {
            const apiOrganization = await this.httpClient.get(`organization/${slug}`);
            // Convert API format to application format
            const organization = apiToOrganization(apiOrganization);
            // Update the organization in the store
            this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: slug, value: organization }));
            return organization;
        }
        catch (error) {
            if (error.response && error.response.status === 404) {
                return undefined;
            }
            // Rethrow other errors
            throw error;
        }
    }
    async updateOrganization(slug, params) {
        const apiOrganization = await this.httpClient.put(`organization/${slug}`, {
            body: {
                name: params.name,
                new_slug: params.new_slug,
                description: params.description,
            },
        });
        // Convert API format to application format
        const organization = apiToOrganization(apiOrganization);
        // If the slug was updated, we need to update the ID in the store
        const newSlug = params.new_slug || slug;
        // Update the organization in the store
        this.appDispatch.dispatch(organizationTable.upsertOne({ status: "found", id: newSlug, value: organization }));
        // If slug was changed, remove the old entry
        if (newSlug !== slug) {
            this.appDispatch.dispatch(organizationTable.removeOne(slug));
        }
        return organization;
    }
}
