import { InterestStore } from "../interest/interestStore";
import { errorToLoadable } from "../network/loadable";
import { POLLING_SLOW } from "../polling";
import { apiToUser, apiToUserSimple, } from "./types";
import { userTable, userByLoginTable } from "./usersSlice";
import { InjectionToken } from "@gitbutler/core/context";
export const USER_SERVICE = new InjectionToken("UserService");
export const NEW_USER_SERVICE = new InjectionToken("NewUserService");
export class UserService {
    httpClient;
    appDispatch;
    userInterests = new InterestStore(POLLING_SLOW);
    userByLoginInterests = new InterestStore(POLLING_SLOW);
    constructor(httpClient, appDispatch) {
        this.httpClient = httpClient;
        this.appDispatch = appDispatch;
    }
    getUserInterest(id) {
        return this.userInterests
            .findOrCreateSubscribable({ id }, async () => {
            this.appDispatch.dispatch(userTable.addOne({ status: "loading", id }));
            try {
                const apiUsers = await this.httpClient.post(`user_search`, {
                    body: { id },
                });
                if (apiUsers.length === 0) {
                    this.appDispatch.dispatch(userTable.upsertOne({ status: "not-found", id }));
                    return;
                }
                if (apiUsers.length !== 1) {
                    // should not happen
                    throw new Error(`Expected 1 user, got ${apiUsers.length}`);
                }
                const apiUser = apiUsers[0];
                const user = apiToUser(apiUser);
                this.appDispatch.dispatch(userTable.upsertOne({ status: "found", id, value: user }));
                if (user.login) {
                    this.appDispatch.dispatch(userByLoginTable.upsertOne({ status: "found", id: user.login, value: user.id }));
                }
            }
            catch (error) {
                this.appDispatch.dispatch(userTable.addOne(errorToLoadable(error, id)));
            }
        })
            .createInterest();
    }
    getUserByLoginInterest(login) {
        return this.userByLoginInterests
            .findOrCreateSubscribable({ login }, async () => {
            try {
                const apiUsers = await this.httpClient.post(`user_search`, {
                    body: { login },
                });
                if (apiUsers.length === 0) {
                    this.appDispatch.dispatch(userByLoginTable.upsertOne({ status: "not-found", id: login }));
                    return;
                }
                if (apiUsers.length !== 1) {
                    // should not happen
                    throw new Error(`Expected 1 user, got ${apiUsers.length}`);
                }
                const apiUser = apiUsers[0];
                const user = apiToUser(apiUser);
                this.appDispatch.dispatch(userByLoginTable.upsertOne({ status: "found", id: login, value: user.id }));
                this.appDispatch.dispatch(userTable.upsertOne({ status: "found", id: user.id, value: user }));
            }
            catch (error) {
                this.appDispatch.dispatch(userByLoginTable.addOne(errorToLoadable(error, login)));
            }
        })
            .createInterest();
    }
    async searchUsers(params) {
        const apiUsers = await this.httpClient.post(`user_search`, {
            body: params,
        });
        // Store the found users in the redux store
        const users = apiUsers.map(apiToUser);
        const loadableUsers = users.map((user) => ({ status: "found", id: user.id, value: user }));
        this.appDispatch.dispatch(userTable.upsertMany(loadableUsers));
        const loadableUsersByLogin = users
            .map((user) => {
            if (!user.login)
                return undefined;
            return { status: "found", id: user.login, value: user.id };
        })
            .filter((loadable) => !!loadable);
        this.appDispatch.dispatch(userByLoginTable.upsertMany(loadableUsersByLogin));
        return apiUsers.map(apiToUserSimple);
    }
}
