import { branchReviewListingTable } from "../branches/branchReviewListingsSlice";
import { branchTable } from "../branches/branchesSlice";
import { latestBranchLookupTable } from "../branches/latestBranchLookupSlice";
import { chatChannelTable } from "../chat/chatChannelsSlice";
import { feedsReducer } from "../feeds/feedsSlice";
import { postsReducer } from "../feeds/postsSlice";
import { organizationTable } from "../organizations/organizationsSlice";
import { projectTable } from "../organizations/projectsSlice";
import { recentlyInteractedProjectIdsReducer } from "../organizations/recentlyInteractedProjectIds";
import { recentlyPushedProjectIdsReducer } from "../organizations/recentlyPushedProjectIds";
import { repositoryIdLookupTable } from "../organizations/repositoryIdLookupsSlice";
import { patchEventsReducer } from "../patchEvents/patchEventsSlice";
import { patchCommitTable } from "../patches/patchCommitsSlice";
import { patchIdableTable } from "../patches/patchIdablesSlice";
import { patchSectionsReducer } from "../patches/patchSectionsSlice";
import { exampleReducer } from "./example";
import { rulesTable } from "../rules/rulesSlice";
import { notificationSettingsTable } from "../settings/notificationSetttingsSlice";
import { userByLoginTable, userTable } from "../users/usersSlice";
import { InjectionToken } from "@gitbutler/core/context";
import { configureStore, createSelector } from "@reduxjs/toolkit";
export const APP_DISPATCH = new InjectionToken("AppDispatch");
export class AppDispatch {
    dispatch;
    constructor(dispatch) {
        this.dispatch = dispatch;
    }
}
export const APP_STATE = new InjectionToken("AppState");
export class AppState {
    reducers = {
        examples: exampleReducer,
        posts: postsReducer,
        feeds: feedsReducer,
        orgnaizations: organizationTable.reducer,
        users: userTable.reducer,
        usersByLogin: userByLoginTable.reducer,
        projects: projectTable.reducer,
        patches: patchCommitTable.reducer,
        patchEvents: patchEventsReducer,
        branches: branchTable.reducer,
        patchSections: patchSectionsReducer,
        chatChannels: chatChannelTable.reducer,
        repositoryIdLookups: repositoryIdLookupTable.reducer,
        latestBranchLookups: latestBranchLookupTable.reducer,
        branchReviewListings: branchReviewListingTable.reducer,
        notificationSettings: notificationSettingsTable.reducer,
        patchIdables: patchIdableTable.reducer,
        recentlyInteractedProjectIds: recentlyInteractedProjectIdsReducer,
        recentlyPushedProjectIds: recentlyPushedProjectIdsReducer,
        rules: rulesTable.reducer,
    };
    /**
     * The base store.
     *
     * This is a low level API and should not be used directly.
     * @private
     */
    _store = configureStore({
        reducer: this.reducers,
    });
    appDispatch = new AppDispatch(this._store.dispatch);
    /**
     * Used to access the store directly. It is recommended to access state via
     * selectors as they are more efficient.
     */
    rootState = $state(this._store.getState());
    selectSelf(state) {
        return state;
    }
    selectExample = createSelector([this.selectSelf], (rootState) => rootState.examples);
    selectPosts = createSelector([this.selectSelf], (rootState) => rootState.posts);
    selectFeeds = createSelector([this.selectSelf], (rootState) => rootState.feeds);
    selectOrganizations = createSelector([this.selectSelf], (rootState) => rootState.orgnaizations);
    selectUsers = createSelector([this.selectSelf], (rootState) => rootState.users);
    selectUsersByLogin = createSelector([this.selectSelf], (rootState) => rootState.usersByLogin);
    selectProjects = createSelector([this.selectSelf], (rootState) => rootState.projects);
    selectPatches = createSelector([this.selectSelf], (rootState) => rootState.patches);
    selectPatchEvents = createSelector([this.selectSelf], (rootState) => rootState.patchEvents);
    selectBranches = createSelector([this.selectSelf], (rootState) => rootState.branches);
    selectPatchSections = createSelector([this.selectSelf], (rootState) => rootState.patchSections);
    selectChatChannels = createSelector([this.selectSelf], (rootState) => rootState.chatChannels);
    selectRepositoryIdLookups = createSelector([this.selectSelf], (rootState) => rootState.repositoryIdLookups);
    selectLatestBranchLookups = createSelector([this.selectSelf], (rootState) => rootState.latestBranchLookups);
    selectBranchReviewListings = createSelector([this.selectSelf], (rootState) => rootState.branchReviewListings);
    selectNotificationSettings = createSelector([this.selectSelf], (rootState) => rootState.notificationSettings);
    selectPatchIdables = createSelector([this.selectSelf], (rootState) => rootState.patchIdables);
    selectRecentlyInteractedProjectIds = createSelector([this.selectSelf], (rootState) => rootState.recentlyInteractedProjectIds);
    selectRecentlyPushedProjectIds = createSelector([this.selectSelf], (rootState) => rootState.recentlyPushedProjectIds);
    selectRules = createSelector([this.selectSelf], (rootState) => rootState.rules);
    example = $derived(this.selectExample(this.rootState));
    posts = $derived(this.selectPosts(this.rootState));
    feeds = $derived(this.selectFeeds(this.rootState));
    organizations = $derived(this.selectOrganizations(this.rootState));
    users = $derived(this.selectUsers(this.rootState));
    usersByLogin = $derived(this.selectUsersByLogin(this.rootState));
    projects = $derived(this.selectProjects(this.rootState));
    patches = $derived(this.selectPatches(this.rootState));
    patchEvents = $derived(this.selectPatchEvents(this.rootState));
    branches = $derived(this.selectBranches(this.rootState));
    patchSections = $derived(this.selectPatchSections(this.rootState));
    chatChannels = $derived(this.selectChatChannels(this.rootState));
    repositoryIdLookups = $derived(this.selectRepositoryIdLookups(this.rootState));
    latestBranchLookups = $derived(this.selectLatestBranchLookups(this.rootState));
    branchReviewListings = $derived(this.selectBranchReviewListings(this.rootState));
    notificationSettings = $derived(this.selectNotificationSettings(this.rootState));
    patchIdables = $derived(this.selectPatchIdables(this.rootState));
    recentlyInteractedProjectIds = $derived(this.selectRecentlyInteractedProjectIds(this.rootState));
    recentlyPushedProjectIds = $derived(this.selectRecentlyPushedProjectIds(this.rootState));
    rules = $derived(this.selectRules(this.rootState));
    constructor() {
        $effect(() => {
            const unsubscribe = this._store.subscribe(() => {
                this.rootState = this._store.getState();
            });
            return unsubscribe;
        });
    }
}
