import { createSelector, createSlice } from "@reduxjs/toolkit";
const initialState = {
    value: 0,
};
const exampleSlice = createSlice({
    name: "example",
    initialState,
    reducers: {
        increment: (state) => {
            state.value += 1;
        },
        decrement: (state) => {
            state.value -= 1;
        },
    },
});
export const { increment, decrement } = exampleSlice.actions;
export const exampleReducer = exampleSlice.reducer;
export function selectExample(example) {
    return example;
}
export const selectExampleValue = createSelector([selectExample], (example) => example.value);
export const selectExampleValueGreaterThan = createSelector([selectExampleValue, (_state, target) => target], (value, target) => value > target);
