import { ApiError, toSerializable } from "./types";
export function isFound(loadable) {
    return loadable?.status === "found";
}
export function isError(loadable) {
    return loadable?.status === "error";
}
export function isNotFound(loadable) {
    return loadable?.status === "not-found";
}
export function errorToLoadable(error, id) {
    if (error instanceof Error) {
        if (error instanceof ApiError && error.response.status === 404) {
            return { status: "not-found", id };
        }
        return { status: "error", id, error: toSerializable(error) };
    }
    return { status: "error", id, error: toSerializable(error) };
}
export function loadableUpsert(adapter) {
    return (state, action) => {
        loadableUpsertMany(adapter)(state, { payload: [action.payload] });
    };
}
export function loadableUpsertMany(adapter) {
    return (state, action) => {
        const values = action.payload.map((payload) => {
            const entity = state.entities[payload.id];
            if (entity === undefined) {
                return payload;
            }
            if (!(entity.status === "found" && payload.status === "found")) {
                return payload;
            }
            let merged;
            const unmergableTypes = ["string", "number", "boolean", "bigint", "symbol", "undefined"];
            if (unmergableTypes.includes(typeof entity.value) ||
                unmergableTypes.includes(typeof payload.value)) {
                merged = payload.value;
            }
            else if (Array.isArray(entity.value) || Array.isArray(payload.value)) {
                merged = payload.value;
            }
            else {
                merged = { ...entity.value };
                for (const [key, value] of Object.entries(payload.value)) {
                    if (value !== undefined && value !== null) {
                        // @ts-expect-error This is fine
                        merged[key] = value;
                    }
                }
            }
            const newValue = {
                status: "found",
                id: payload.id,
                value: merged,
            };
            return newValue;
        });
        adapter.setMany(state, values);
    };
}
export function and(loadables) {
    if (loadables.length <= 1) {
        return loadables[0];
    }
    if (isFound(loadables[0])) {
        return and(loadables.slice(1));
    }
    else {
        return loadables[0];
    }
}
export function map(loadable, digger) {
    if (isFound(loadable)) {
        return digger(loadable.value);
    }
    return undefined;
}
export function mapL(loadable, digger) {
    if (isFound(loadable)) {
        return { status: "found", value: digger(loadable.value) };
    }
    return loadable;
}
export function combine(loadables) {
    if (loadables.every((loadable) => isFound(loadable))) {
        return {
            status: "found",
            // @ts-expect-error I'm sure this could be typed properly, but this is fine
            value: loadables.map((loadable) => loadable.value),
        };
    }
    const failureStates = [isError, isNotFound];
    for (const state of failureStates) {
        for (const loadable of loadables) {
            if (state(loadable)) {
                return loadable;
            }
        }
    }
    return { status: "loading" };
}
