<script lang="ts" module>
	// This module script is necessary to make Svelte recognize the generics in the component
	export type Page = {
		id: string;
		label: string;
		icon: IconName;
		adminOnly?: boolean;
		[key: string]: any; // Allow additional properties for flexibility
	};
</script>

<script lang="ts" generics="T extends Page">
	import AppScrollableContainer from "$components/shared/AppScrollableContainer.svelte";
	import { Icon, type IconName } from "@gitbutler/ui";
	import { focusable } from "@gitbutler/ui/focus/focusable";
	import { type Snippet } from "svelte";

	type PageId = T["id"];

	type Props = {
		title: string;
		pages: readonly T[];
		selectedId?: PageId;
		isAdmin?: boolean;
		onSelectPage: (pageId: PageId) => void;
		content: Snippet<[{ currentPage: Page | undefined }]>;
		footer?: Snippet;
	};

	const { title, pages, selectedId, isAdmin, onSelectPage, content, footer }: Props = $props();

	let currentSelectedId = $derived(selectedId || pages[0]?.id || "");
	const currentPage = $derived(pages.find((p) => p.id === currentSelectedId));
	let scrollableContainer: AppScrollableContainer;

	function selectPage(pageId: string) {
		currentSelectedId = pageId;
		onSelectPage(pageId);
	}

	$effect(() => {
		if (currentSelectedId) {
			scrollableContainer?.scrollToTop();
		}
	});
</script>

<div class="modal-settings-wrapper">
	<div class="settings-sidebar__wrapper">
		<div class="settings-sidebar" use:focusable>
			<h3 class="settings-sidebar__title text-16 text-bold">{title}</h3>
			<div class="settings-sidebar__links">
				{#each pages.filter((p) => !p.adminOnly || isAdmin) as page}
					{@const selected = page.id === currentSelectedId}
					<button
						type="button"
						class="text-14 text-semibold settings-sidebar__links-item"
						class:selected
						onclick={() => selectPage(page.id)}
					>
						<div class="settings-sidebar__links-item__icon">
							<Icon name={page.icon} />
						</div>
						<span>{page.label}</span>
					</button>
				{/each}
			</div>

			{#if footer}
				<div class="settings-sidebar__footer">
					{@render footer()}
				</div>
			{/if}
		</div>
	</div>

	<section class="page-view" use:focusable={{ vertical: true }}>
		<AppScrollableContainer bind:this={scrollableContainer}>
			<div class="page-view__content">
				{@render content({ currentPage })}
			</div>
		</AppScrollableContainer>
	</section>
</div>

