import { apiToBranch } from "../branches/types";
import { InterestStore } from "../interest/interestStore";
import { errorToLoadable } from "../network/loadable";
import { projectTable } from "./projectsSlice";
import { updateRecentlyInteractedProjectIds } from "./recentlyInteractedProjectIds";
import { updateRecentlyPushedProjectIds } from "./recentlyPushedProjectIds";
import { apiToProject, } from "./types";
import { POLLING_GLACIALLY, POLLING_REGULAR } from "../polling";
import { InjectionToken } from "@gitbutler/core/context";
function toApiUpdateParams(real) {
    return {
        slug: real.slug,
        name: real.name,
        description: real.description,
        readme: real.readme,
        share_level: real.shareLevel,
    };
}
export const PROJECT_SERVICE = new InjectionToken("ProjectService");
export class ProjectService {
    httpClient;
    appDispatch;
    projectInterests = new InterestStore(POLLING_REGULAR);
    userProjectsInterests = new InterestStore(POLLING_GLACIALLY);
    recentProjectsInterests = new InterestStore(POLLING_GLACIALLY);
    recentlyPushedProjectsInterests = new InterestStore(POLLING_GLACIALLY);
    constructor(httpClient, appDispatch) {
        this.httpClient = httpClient;
        this.appDispatch = appDispatch;
    }
    getProjectInterest(repositoryId) {
        return this.projectInterests
            .findOrCreateSubscribable({ repositoryId }, async () => {
            this.appDispatch.dispatch(projectTable.addOne({ status: "loading", id: repositoryId }));
            try {
                const apiProject = await this.httpClient.get(`projects/${repositoryId}`);
                this.appDispatch.dispatch(projectTable.upsertOne({
                    status: "found",
                    id: repositoryId,
                    value: apiToProject(apiProject),
                }));
            }
            catch (error) {
                this.appDispatch.dispatch(projectTable.addOne(errorToLoadable(error, repositoryId)));
            }
        })
            .createInterest();
    }
    async getProject(repositoryId) {
        try {
            const apiProject = await this.httpClient.get(`projects/${repositoryId}`);
            this.appDispatch.dispatch(projectTable.upsertOne({
                status: "found",
                id: repositoryId,
                value: apiToProject(apiProject),
            }));
            return apiToProject(apiProject);
        }
        catch (_) {
            /* empty */
        }
    }
    async getProjectBySlug(slug) {
        try {
            const apiProject = await this.httpClient.get(`projects/full/${slug}`);
            this.appDispatch.dispatch(projectTable.upsertOne({
                status: "found",
                id: apiProject.repository_id,
                value: apiToProject(apiProject),
            }));
            return apiToProject(apiProject);
        }
        catch (_) {
            /* empty */
        }
    }
    /**
     * Get patch stacks for a project by its full slug
     * @param slug The project's full slug (owner/project)
     * @returns Array of Branch objects
     */
    async getProjectPatchStacks(slug) {
        try {
            const apiBranches = await this.httpClient.get(`patch_stack/${slug}`);
            return apiBranches.map(apiToBranch);
        }
        catch (error) {
            console.error(`Error fetching patch stacks for ${slug}:`, error);
            return [];
        }
    }
    getAllProjectsInterest() {
        return this.userProjectsInterests
            .findOrCreateSubscribable({ unused: "unused" }, async () => {
            const apiProjects = await this.httpClient.get("projects");
            const projects = apiProjects.map((apiProject) => ({
                status: "found",
                id: apiProject.repository_id,
                value: apiToProject(apiProject),
            }));
            this.appDispatch.dispatch(projectTable.upsertMany(projects));
        })
            .createInterest();
    }
    getRecentProjectsInterest() {
        return this.recentProjectsInterests
            .findOrCreateSubscribable({ unused: "unused" }, async () => {
            const apiProjects = await this.httpClient.get("projects/recently_interacted");
            const projects = apiProjects.map((apiProject) => ({
                status: "found",
                id: apiProject.repository_id,
                value: apiToProject(apiProject),
            }));
            this.appDispatch.dispatch(projectTable.upsertMany(projects));
            this.appDispatch.dispatch(updateRecentlyInteractedProjectIds(projects.map((project) => project.id)));
        })
            .createInterest();
    }
    getRecentlyPushedProjectsInterest() {
        return this.recentlyPushedProjectsInterests
            .findOrCreateSubscribable({ unused: "unused" }, async () => {
            const apiProjects = await this.httpClient.get("projects/recently_pushed");
            const projects = apiProjects.map((apiProject) => ({
                status: "found",
                id: apiProject.repository_id,
                value: apiToProject(apiProject),
            }));
            this.appDispatch.dispatch(projectTable.upsertMany(projects));
            this.appDispatch.dispatch(updateRecentlyPushedProjectIds(projects.map((project) => project.id)));
        })
            .createInterest();
    }
    async createProject(name, description) {
        const apiProject = await this.httpClient.post("projects", {
            body: { name, description },
        });
        const project = apiToProject(apiProject);
        this.appDispatch.dispatch(projectTable.upsertOne({ status: "found", id: project.repositoryId, value: project }));
        return project;
    }
    async connectProjectToOrganization(repositoryId, organizationSlug, targetRepositorySlug) {
        const apiProject = await this.httpClient.post(`projects/${repositoryId}/connect`, {
            body: {
                organization_slug: organizationSlug,
                project_slug: targetRepositorySlug,
            },
        });
        const project = apiToProject(apiProject);
        this.appDispatch.dispatch(projectTable.upsertOne({ status: "found", id: project.repositoryId, value: project }));
        return project;
    }
    async deleteProject(repositoryId) {
        await this.httpClient.delete(`projects/${repositoryId}`);
        this.appDispatch.dispatch(projectTable.removeOne(repositoryId));
    }
    async updateProject(repositoryId, params) {
        const apiProject = await this.httpClient.patch(`projects/${repositoryId}`, {
            body: toApiUpdateParams(params),
        });
        const project = apiToProject(apiProject);
        this.appDispatch.dispatch(projectTable.upsertOne({ status: "found", id: project.repositoryId, value: project }));
        return project;
    }
    async disconnectProject(repositoryId) {
        const apiProject = await this.httpClient.post(`projects/${repositoryId}/disconnect`);
        const project = apiToProject(apiProject);
        this.appDispatch.dispatch(projectTable.upsertOne({ status: "found", id: project.repositoryId, value: project }));
        return project;
    }
}
