		transform: translateY(4px);
		color: var(--text-2);
	}

	.commit-failed__file-entry-dependencies {
		display: flex;
		flex-direction: column;
		padding: 0 12px 12px;
		gap: 10px;
	}

	/* File entry */
	.commit-failed__file-entry {
		display: flex;
