export function shallowCompare(left, right) {
    if (left === right) {
        return true;
    }
    if (typeof left !== "object" ||
        typeof right !== "object" ||
        left === undefined ||
        right === undefined ||
        left === null ||
        right === null) {
        return false;
    }
    const keys1 = Object.keys(left);
    const keys2 = Object.keys(right);
    if (keys1.length !== keys2.length) {
        return false;
    }
    for (const key of keys1) {
        if (left[key] !== right[key]) {
            return false;
        }
    }
    return true;
}
export function deepCompare(left, right) {
    if (left === right) {
        return true;
    }
    if (typeof left !== "object" ||
        typeof right !== "object" ||
        left === undefined ||
        right === undefined ||
        left === null ||
        right === null) {
        return false;
    }
    if (Array.isArray(left) !== Array.isArray(right)) {
        return false;
    }
    const keys1 = Object.keys(left);
    const keys2 = Object.keys(right);
    if (keys1.length !== keys2.length) {
        return false;
    }
    for (const key of keys1) {
        if (!keys2.includes(key)) {
            return false;
        }
        if (!deepCompare(left[key], right[key])) {
            return false;
        }
    }
    return true;
}
