export function isApiUserSimple(data) {
    return (typeof data === "object" &&
        data !== null &&
        typeof data.id === "number" &&
        (typeof data.avatar_url === "string" || data.avatar_url === null) &&
        (typeof data.email === "string" || data.email === null) &&
        (typeof data.login === "string" || data.login === null) &&
        (typeof data.name === "string" || data.name === null));
}
export function apiToUserSimple(api) {
    return {
        id: api.id,
        avatarUrl: api.avatar_url ?? undefined,
        email: api.email ?? undefined,
        login: api.login ?? undefined,
        name: api.name ?? undefined,
    };
}
export function apiToUserMaybe(api) {
    return {
        email: api.email,
        user: api.user ? apiToUserSimple(api.user) : undefined,
    };
}
export function apiToUser(apiUser) {
    return {
        ...apiToUserSimple(apiUser),
        website: apiUser.website,
        twitter: apiUser.twitter,
        bluesky: apiUser.bluesky,
        timezone: apiUser.timezone,
        location: apiUser.location,
    };
}
export function apiToUserPrivate(api) {
    return {
        ...apiToUser(api),
        accessToken: api.access_token,
        role: api.role ?? undefined,
    };
}
