export function registerInterest(interest, inView) {
    if (inView) {
        registerInterestInView(interest, inView.element);
    }
    else {
        registerInterestAlways(interest);
    }
}
export function registerInterestAlways(interest) {
    $effect(() => {
        const unsubscribe = interest._subscribe();
        return unsubscribe;
    });
}
export function registerInterestInView(interest, element) {
    let inView = $state(false);
    $effect(() => {
        if (element) {
            inView = false;
            const observer = new IntersectionObserver((entries) => {
                inView = entries[0]?.isIntersecting || false;
            }, {
                root: null,
            });
            observer.observe(element);
            return () => {
                inView = false;
                observer.disconnect();
            };
        }
        else {
            inView = false;
        }
    });
    $effect(() => {
        if (inView) {
            registerInterestAlways(interest);
        }
    });
}
