import { shallowCompare } from "../compare";
import { asyncToSyncSignals } from "../storeUtils";
class PollingSubscription {
    args;
    upsert;
    frequency;
    counter = 0;
    lastCalled = 0;
    interval;
    unsubscribe;
    constructor(args, upsert, frequency) {
        this.args = args;
        this.upsert = upsert;
        this.frequency = frequency;
    }
    createInterest() {
        return {
            _subscribe: asyncToSyncSignals(this.subscribe.bind(this)),
        };
    }
    async subscribe() {
        // Fetch data immediately on first subscription
        if (this.counter === 0) {
            // If there is no frequency, then we should always make the initial fetch
            if (Date.now() - this.lastCalled > this.frequency) {
                this.lastCalled = Date.now();
                this.unsubscribe = (await this.upsert()) || undefined;
            }
            this.interval = setInterval(async () => {
                this.lastCalled = Date.now();
                this.unsubscribe = (await this.upsert()) || undefined;
            }, this.frequency);
        }
        ++this.counter;
        // Unsubscribe function
        return async () => {
            --this.counter;
            if (this.counter <= 0) {
                clearInterval(this.interval);
                await this.unsubscribe?.();
            }
        };
    }
    async refetch() {
        await this.upsert();
    }
}
class ListeningSubscription {
    args;
    upsert;
    counter = 0;
    unsubscribe;
    constructor(args, upsert) {
        this.args = args;
        this.upsert = upsert;
    }
    createInterest() {
        return {
            _subscribe: asyncToSyncSignals(this.subscribe.bind(this)),
        };
    }
    async subscribe() {
        // Fetch data immediately on first subscription
        if (this.counter === 0) {
            this.unsubscribe = (await this.upsert()) || undefined;
        }
        ++this.counter;
        // Unsubscribe function
        return async () => {
            --this.counter;
            if (this.counter <= 0) {
                await this.unsubscribe?.();
            }
        };
    }
    async refetch() {
        // Refetch does not make sense for listening subscriptions
        throw new Error("Refetch can not be called on ListeningSubscription");
    }
}
/**
 * The interest store is responsible for managing the subscriptions produced by
 * given service. There will only ever be one interest for each set of `args`
 * provided. This allows us to avoid making duplicate or supuflous requests.
 *
 * If it's constructed with a `frequency` the start notifier will get called first
 * when the subscription is first registered, and then many subsequent times,
 * until it is no longer registered.
 *
 * If it's constructed without a `frequency`, the start notifier will only get
 * called once before it's stop notifier is called.
 */
export class InterestStore {
    frequency;
    subscriptions = [];
    constructor(frequency) {
        this.frequency = frequency;
    }
    findOrCreateSubscribable(args, upsert) {
        let subscription = this.subscriptions.find((subscription) => shallowCompare(subscription.args, args));
        if (!subscription) {
            if (this.frequency) {
                subscription = new PollingSubscription(args, upsert, this.frequency);
            }
            else {
                subscription = new ListeningSubscription(args, upsert);
            }
            this.subscriptions.push(subscription);
        }
        return subscription;
    }
    async invalidate(args) {
        const subscription = this.subscriptions.find((subscription) => shallowCompare(subscription.args, args));
        if (subscription) {
            await subscription.refetch();
        }
    }
}
