import { registerInterest } from "../interest/registerInterestFunction.svelte";
import { isFound, map } from "../network/loadable";
import { PROJECT_SERVICE } from "./projectService";
import { projectTable } from "./projectsSlice";
import { lookupProject } from "./repositoryIdLookupPreview.svelte";
import { reactive } from "../reactiveUtils.svelte";
import { APP_STATE } from "../redux/store.svelte";
import {} from "../storeUtils";
import { inject } from "@gitbutler/core/context";
import { isDefined } from "@gitbutler/ui/utils/typeguards";
export function getProject(ownerSlug, projectSlug, inView) {
    const repositoryId = lookupProject(ownerSlug, projectSlug, inView);
    const current = $derived(map(repositoryId.current, (repositoryId) => getProjectByRepositoryId(repositoryId, inView)));
    return reactive(() => current?.current);
}
export function getProjectByRepositoryId(projectRepositoryId, inView) {
    const appState = inject(APP_STATE);
    const projectService = inject(PROJECT_SERVICE);
    registerInterest(projectService.getProjectInterest(projectRepositoryId), inView);
    const current = $derived(projectTable.selectors.selectById(appState.projects, projectRepositoryId));
    return reactive(() => current);
}
export function getAllUserProjects(user, inView) {
    const appState = inject(APP_STATE);
    const projectService = inject(PROJECT_SERVICE);
    registerInterest(projectService.getAllProjectsInterest(), inView);
    const current = $derived.by(() => {
        const allProjects = projectTable.selectors.selectAll(appState.projects);
        return allProjects.filter((project) => isFound(project) && project.value.owner === user);
    });
    return reactive(() => current);
}
export function getRecentlyInteractedProjects(inView) {
    const appState = inject(APP_STATE);
    const projectService = inject(PROJECT_SERVICE);
    registerInterest(projectService.getRecentProjectsInterest(), inView);
    const current = $derived(appState.recentlyInteractedProjectIds.recentlyInteractedProjectIds
        .map((recentProjectId) => projectTable.selectors.selectById(appState.projects, recentProjectId))
        .filter(isDefined));
    return reactive(() => current);
}
export function getRecentlyPushedProjects(inView) {
    const appState = inject(APP_STATE);
    const projectService = inject(PROJECT_SERVICE);
    registerInterest(projectService.getRecentlyPushedProjectsInterest(), inView);
    const current = $derived(appState.recentlyPushedProjectIds.recentlyPushedProjectIds
        .map((recentProjectId) => projectTable.selectors.selectById(appState.projects, recentProjectId))
        .filter(isDefined));
    return reactive(() => current);
}
export function getParentForRepositoryId(projectRepositoryId, inView) {
    const current = $derived.by(() => {
        const project = getProjectByRepositoryId(projectRepositoryId, inView);
        if (!isFound(project.current) || !project.current.value.parentProjectRepositoryId)
            return;
        return getProjectByRepositoryId(project.current.value.parentProjectRepositoryId, inView);
    });
    return reactive(() => current?.current);
}
export function getFeedIdentityForRepositoryId(projectRepositoryId, inView) {
    const parentProject = $derived(getParentForRepositoryId(projectRepositoryId, inView));
    const current = $derived.by(() => {
        if (!isFound(parentProject.current))
            return parentProject.current || { status: "loading" };
        return {
            status: "found",
            value: `${parentProject.current.value.owner}/${parentProject.current.value.slug}`,
        };
    });
    return reactive(() => current);
}
